        {{-- ── Task 2 Band 7 ── --}}
        <div class="card p-6 sm:p-8">
            <div class="flex flex-wrap items-center gap-3 mb-5">
                <span class="inline-flex items-center gap-1.5 bg-amber-500/15 text-amber-400 border border-amber-500/30 text-xs font-bold px-3 py-1 rounded-full">
                    Band 7
                </span>
                <span class="inline-flex items-center gap-1.5 bg-rose-500/15 text-rose-400 border border-rose-500/30 text-xs font-semibold px-3 py-1 rounded-full">
                    Task 2 — Opinion Essay
                </span>
                <span class="ml-auto text-xs text-surface-500">~260 words</span>
